INSERT INTO `recommend_questions` (`id`, `emoji`, `question`, `reason`, `category_id`, `question_order`) VALUES
(1, '🌸', 'Cơ thể tớ dạo này thay đổi lạ lẫm quá...', 'Tuổi dậy thì đem tới rất nhiều thay đổi thú vị về cả cơ thể và tâm lý. Đừng lo lắng, khóa học này sẽ đồng hành cùng bạn tìm hiểu chi tiết và yêu thương cơ thể mình hơn nhé!', 1, 10),
(2, '🛑', 'Làm sao để nói Không và bảo vệ ranh giới?', 'Biết cách check-in sự đồng thuận và dũng cảm từ chối những điều mình không thoải mái là kỹ năng cực kỳ ngầu. Xem ngay lộ trình ranh giới dưới đây nhé.', 2, 20),
(3, '🧠', 'Dạo này tớ hay bị stress, dễ nhạy cảm và buồn...', 'Cảm xúc thay đổi thất thường là chuyện siêu bình thường tuổi teen. Khóa học dưới đây sẽ giúp bạn học cách lắng nghe bản thân và điều hòa áp lực học tập hiệu quả.', 3, 30),
(4, '🛡️', 'Có nên đưa mật khẩu tài khoản cho người yêu không?', 'Ranh giới cá nhân trên mạng xã hội là cực kỳ quan trọng để bảo vệ bản thân. Cùng khám phá các quy tắc an toàn số dưới đây để không bị kiểm soát hay lo sợ nha.', 4, 40),
(5, '💬', 'Tình bạn/tình yêu của tụi mình có thực sự lành mạnh?', 'Hiểu rõ các dấu hiệu Green Flag và cách giao tiếp tự tin sẽ giúp bạn xây dựng những kết nối bền vững, tôn trọng lẫn nhau. Tham khảo lộ trình này nha.', 5, 50);
INSERT INTO `courses` (`id`, `title`, `description`, `thumbnail`, `color_theme`, `course_order`, `category_id`, `created_at`, `updated_at`) VALUES
(4, 'Tự Tin Lớn Lên, Tự Chủ Khám Phá', 'Khóa học về sự đồng thuận, ranh giới cá nhân và phát triển lành mạnh dành cho tuổi teen.', 'consent-course.png', '#4361ee', 10, 2, '2026-06-05 01:35:30', '2026-06-05 01:35:30'),
(5, 'Mối Quan Hệ Lành Mạnh', 'Tìm hiểu về cách xây dựng tình bạn, tình yêu tôn trọng, đặt ranh giới cá nhân và ứng xử văn minh trước cờ đỏ.', 'relationship-course.png', '#ff5d8f', 20, 5, '2026-06-05 10:27:59', '2026-06-05 10:27:59'),
(6, 'Lướt Mạng Tỉnh Táo, Kết Nối Cực Chất', 'Tìm hiểu cách bảo vệ quyền riêng tư, thiết lập ranh giới số, hiểu về sự đồng thuận trực tuyến, chia sẻ ảnh an toàn và ứng phó với cờ đỏ thao túng.', 'digital-safety-course.png', '#7209b7', 21, 4, '2026-06-05 12:18:20', '2026-06-05 12:18:20'),
(10, 'Dậy Thì Thành Công: Cẩm Nang \"Upgrade\" Bản Thân!', 'Tìm hiểu về thay đổi thể chất, hệ sinh sản, kinh nguyệt, mộng tinh, bão cảm xúc và cách tự chăm sóc cơ thể tuổi dậy thì.', 'puberty-course.png', '#f77f00', 22, 1, '2026-06-05 13:58:05', '2026-06-05 13:58:05'),
(11, 'Tâm Lý Tuổi Teen: \"Gỡ Rối\" Bão Cảm Xúc!', 'Học cách nhận diện và làm quen với những biến động cảm xúc tuổi dậy thì, xây dựng sự tự tin, ứng phó áp lực học tập và nuôi dưỡng các mối quan hệ lành mạnh.', 'emotional-wellbeing-course.png', '#06d6a0', 23, 3, '2026-06-05 15:00:15', '2026-06-05 15:00:15');
